import assert from "node:assert";
import { tokenizeCommand } from "../src/index.mjs";

assert.deepStrictEqual(tokenizeCommand("deploy service --env prod"), ["deploy", "service", "--env", "prod"]);
assert.deepStrictEqual(tokenizeCommand("deploy \"billing api\" --env prod"), ["deploy", "billing api", "--env", "prod"]);
assert.deepStrictEqual(tokenizeCommand("   \"two words\"    done   "), ["two words", "done"]);
assert.deepStrictEqual(tokenizeCommand("   "), []);
assert.throws(() => tokenizeCommand("deploy \"billing api"), /Unclosed quote/);
